struct Package {
    sender: String,
    recipient: String,
    weight_in_grams: i32,
}

impl Package {
    fn new(sender: String, recipient: String, weight_in_grams: i32) -> Package {
        if weight_in_grams <= 0 {
            panic!("Weight must be positive!");
        }
        Package {
            sender,
            recipient,
            weight_in_grams,
        }
    }

    fn is_international(&self) -> bool {
        self.sender.split(", ").last() != self.recipient.split(", ").last()
    }

    fn get_fees(&self, cents_per_gram: i32) -> i32 {
        self.weight_in_grams * cents_per_gram
    }
}

fn main() {
    let package = Package::new(
        "Alice, US".to_string(),
        "Bob, JP".to_string(),
        500,
    );
    println!("International: {}", package.is_international());
    println!("Fees: {} cents", package.get_fees(2));
}
